// Shape the webhook body for the AI Agent node.
//
// History comes from the BROWSER (it already has the transcript), which keeps this
// flow stateless - no memory node, no session store. We fold the last few turns
// into the system message so the agent still follows the conversation.

const body = $input.first().json.body || {};
const message = (body.message || '').toString().trim();
const history = Array.isArray(body.history) ? body.history.slice(-6) : [];

const SYSTEM = "You are Aria, the friendly AI receptionist for Tertiary Infotech Academy, speaking to a visitor through a talking avatar.

VOICE RULES - you are SPOKEN ALOUD:
- One short sentence; two at the very most.
- Plain spoken English. No markdown, no bullets, no emoji, no URLs, no code.
- Say numbers in words: "two days", "nine thirty in the morning".

CONVERSATION RULES:
- ALWAYS give a helpful answer. If the question is unclear, give your best answer AND ask one short follow-up question.
- Never say you did not hear or did not catch the message - the message always reaches you perfectly.
- If you truly do not know a fact, say so briefly and offer to have a colleague follow up. Never invent a price, a date or a policy.
- Greet a plain hello warmly and offer help with courses, schedules or enrolment.

WHAT YOU KNOW:
- Tertiary Infotech Academy is a Singapore training provider for working adults.
- It runs WSQ short courses in AI, automation and data - including building AI chatbots, voice agents and avatar videos with n8n, plus data analytics and programming.
- Courses are hands-on, usually one to three days, from nine thirty in the morning to six thirty in the evening, at the Woods Square training centre in Woodlands.
- SkillsFuture credit and WSQ funding can offset the fees for eligible Singaporeans and PRs.
- To enrol or see the full course list, a learner visits the Tertiary Courses website or speaks to our staff.";

const transcript = history
  .map((h) => `${h.role === 'you' ? 'Visitor' : 'Aria'}: ${h.text}`)
  .join('
');

return [{ json: {
  chatInput: message || 'Hello',
  system: transcript ? `${SYSTEM}

CONVERSATION SO FAR
${transcript}` : SYSTEM,
  warm: !!body.warm,
  started_at: Date.now(),  // the agent reports no timings, so we measure wall-clock ourselves
} }];

// The avatar SPEAKS this, so strip anything that does not read aloud: a stray
// asterisk becomes an audible "asterisk", and a thinking model's private
// reasoning must never reach the voice.
const res = $input.first().json;
const started = $('Build Prompt').first().json.started_at;

let reply = (res.output ?? res.text ?? res.response ?? '').toString();

reply = reply
  .replace(/<think>[\s\S]*?<\/think>/gi, '')   // a thinking model's inner monologue
  .replace(/[*_`#>]/g, '')
  .replace(/^\s*[-\u2022]\s*/gm, '')
  .replace(/https?:\/\/\S+/g, 'the link on our website')
  .replace(/\s+/g, ' ')
  .trim();

// Never blame the visitor's microphone - the message arrived fine. If the model
// gave us nothing, own the hiccup and keep the conversation alive.
if (!reply) {
  const asked = ($('Build Prompt').first().json.chatInput || '').trim().toLowerCase();
  reply = (!asked || asked === 'hello')
    ? 'Hi, I am Aria. Ask me about our courses, the schedule, or how to enrol.'
    : 'Give me one second, my brain hiccuped there - please ask me that once more.';
}

return [{ json: {
  reply,
  timing: {
    total_ms: started ? Date.now() - started : null,
    model_load_ms: null,
    prompt_ms: null,
    generate_ms: null,
    tokens: 0,
    prompt_tokens: 0,
  },
  // Trainer-facing breadcrumb (the page ignores it): why a fallback fired.
  debug: res.error ? String(res.error).slice(0, 200) : undefined,
} }];
